1	type Cell = [number, number]; // [x, y]
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [0, -1], [1, -1],
5	  [-1, 0], [1, 0],
6	  [-1, 1], [0, 1], [1, 1],
7	];
8	const BIRTH_NEIGHBORS = 3;
9	const SURVIVAL_NEIGHBORS = 2;
10	
11	function key(x: number, y: number): string {
12	  return `${x},${y}`;
13	}
14	
15	function parseKey(cellKey: string): Cell {
16	  const [x, y] = cellKey.split(",").map(Number);
17	  return [x, y];
18	}
19	
20	function countLiveNeighbors(cells: Cell[]): Map<string, number> {
21	  const counts = new Map<string, number>();
22	  for (const [x, y] of cells) {
23	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
24	      const neighbor = key(x + dx, y + dy);
25	      counts.set(neighbor, (counts.get(neighbor) ?? 0) + 1);
26	    }
27	  }
28	  return counts;
29	}
30	
31	function isAliveNextGeneration(
32	  liveNeighbors: number,
33	  isCurrentlyAlive: boolean,
34	): boolean {
35	  if (liveNeighbors === BIRTH_NEIGHBORS) return true;
36	  return liveNeighbors === SURVIVAL_NEIGHBORS && isCurrentlyAlive;
37	}
38	
39	export function nextGeneration(cells: Cell[]): Cell[] {
40	  const living = new Set(cells.map(([x, y]) => key(x, y)));
41	  const neighborCounts = countLiveNeighbors(cells);
42	
43	  const next: Cell[] = [];
44	  for (const [cellKey, count] of neighborCounts) {
45	    if (isAliveNextGeneration(count, living.has(cellKey))) {
46	      next.push(parseKey(cellKey));
47	    }
48	  }
49	  return next;
50	}
51

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("returns an empty array when given no living cells — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("a single living cell dies from underpopulation — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("a pair of living cells both die from underpopulation — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("a dead cell with exactly 3 live neighbors becomes alive (reproduction) — (1,1) joins output", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
16	    expect(result).toContainEqual([1, 1]);
17	  });
18	  it("a live cell with 2 live neighbors survives (survival)", () => {
19	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
20	    expect(result).toContainEqual([1, 0]);
21	  });
22	  it("a live cell with more than 3 live neighbors dies (overpopulation) — center (1,1) dies", () => {
23	    const result = nextGeneration([
24	      [0, 0], [1, 0], [2, 0],
25	      [1, 1],
26	      [0, 2], [1, 2], [2, 2],
27	    ]);
28	    expect(result).not.toContainEqual([1, 1]);
29	  });
30	  it("a block is a still life and stays unchanged — [(0,0),(1,0),(0,1),(1,1)] unchanged", () => {
31	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
32	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
33	      new Set(["0,0", "1,0", "0,1", "1,1"]),
34	    );
35	  });
36	  it.todo("a blinker oscillates — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]");
37	  it.todo("handles negative coordinates correctly");
38	});
